import numpy as np
import time
import torch
import scipy.linalg.blas as blas

def m1(v1, v2):
    return np.outer(v1, v2)

def m2(v1, v2):
    return v1[:, None] * v2

def m3(v1, v2):
    return blas.dger(1.0, v1, v2)

def m4(v1, v2):
    t1 = torch.from_numpy(v1)
    t2 = torch.from_numpy(v2)
    return torch.outer(t1, t2).numpy()

for size in [1000, 5000, 10000]:
    print(f"\nSize: {size}")
    v1 = np.random.rand(size)
    v2 = np.random.rand(size)

    for name, func in [('np.outer', m1), ('v1[:, None] * v2', m2), ('blas.dger', m3), ('torch.outer', m4)]:
        start = time.perf_counter()
        for _ in range(10):
            func(v1, v2)
        end = time.perf_counter()
        print(f"{name}: {(end - start) / 10:.6f} seconds")

